import hashlib


def hash_file(filepath: str, algorithm: str = "sha256", chunk_size: int = 8192) -> str:
    """
    Create a cryptographic hash of a file for integrity checking.

    Args:
        filepath: Path to the file to hash.
        algorithm: Hash algorithm to use (default: sha256).
        chunk_size: Size of chunks to read at a time (default: 8192 bytes).

    Returns:
        Hex digest string of the file hash.

    Raises:
        ValueError: If the algorithm is not supported.
        FileNotFoundError: If the file does not exist.
        OSError: If the file cannot be read.
    """
    supported_algorithms = hashlib.algorithms_guaranteed
    if algorithm not in supported_algorithms:
        raise ValueError(
            f"Unsupported algorithm '{algorithm}'. "
            f"Supported: {sorted(supported_algorithms)}"
        )

    if chunk_size <= 0:
        raise ValueError("chunk_size must be a positive integer")

    h = hashlib.new(algorithm)

    with open(filepath, "rb") as f:
        while True:
            chunk = f.read(chunk_size)
            if not chunk:
                break
            h.update(chunk)

    return h.hexdigest()


def verify_file(filepath: str, expected_hash: str, algorithm: str = "sha256") -> bool:
    """
    Verify a file's integrity by comparing its hash to an expected value.

    Uses constant-time comparison to avoid timing side-channel attacks.

    Args:
        filepath: Path to the file to verify.
        expected_hash: The expected hex digest string.
        algorithm: Hash algorithm to use (default: sha256).

    Returns:
        True if the file hash matches the expected hash, False otherwise.
    """
    actual_hash = hash_file(filepath, algorithm=algorithm)
    return hmac_compare(actual_hash, expected_hash)


def hmac_compare(a: str, b: str) -> bool:
    """Constant-time string comparison to prevent timing attacks."""
    import hmac
    return hmac.compare_digest(a.lower(), b.lower())


